contracts/launch/LinearVestingVaultUpgra.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * LinearVestingVaultUpgradeable (clone-friendly)
 * - Holds ERC20 tokens
 * - Releases to beneficiary after a cliff, then linearly until fully vested at `start + duration`
 * - Uses initializer instead of constructor (for EIP-1167 clones)
 */

import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract LinearVestingVaultUpgradeable is Initializable {
  IERC20 public token;
  address public beneficiary;
  uint64 public start;
  uint64 public cliffSeconds;
  uint64 public durationSeconds;
  uint256 public totalAllocation;

  uint256 public released;

  event Released(uint256 amount, uint256 totalReleased, uint256 remaining);

  function initialize(
    address token_,
    address beneficiary_,
    uint64 start_,
    uint64 cliffSeconds_,
    uint64 durationSeconds_,
    uint256 totalAllocation_
  ) external initializer {
    require(token_ != address(0), "token=0");
    require(beneficiary_ != address(0), "beneficiary=0");
    require(durationSeconds_ > 0, "duration=0");
    require(durationSeconds_ >= cliffSeconds_, "duration < cliff");
    require(totalAllocation_ > 0, "allocation=0");

    token = IERC20(token_);
    beneficiary = beneficiary_;
    start = start_;
    cliffSeconds = cliffSeconds_;
    durationSeconds = durationSeconds_;
    totalAllocation = totalAllocation_;
  }

  function vestedAmount(uint64 timestamp) public view returns (uint256) {
    uint64 cliffTime = start + cliffSeconds;
    if (timestamp < cliffTime) return 0;

    uint64 endTime = start + durationSeconds;
    if (timestamp >= endTime) return totalAllocation;

    // Flow #1: linear vesting starts AFTER the cliff, so the vested amount at cliffTime is 0 (no jump).
    uint256 linearDuration = uint256(durationSeconds - cliffSeconds);
    if (linearDuration == 0) return totalAllocation;
    uint256 elapsedSinceCliff = uint256(timestamp - cliffTime);

    // Calculate vested amount
    uint256 vested = (totalAllocation * elapsedSinceCliff) / linearDuration;

    // If we're very close to the end, return totalAllocation to avoid precision loss
    // This ensures all tokens can be released eventually
    if (elapsedSinceCliff + 1 >= linearDuration) {
      return totalAllocation;
    }

    return vested;
  }

  function releasable() public view returns (uint256) {
    // block.timestamp is uint256, but vestedAmount accepts uint64
    // In practice, uint64 is sufficient until year 2106
    require(block.timestamp <= type(uint64).max, "timestamp overflow");
    uint256 vested = vestedAmount(uint64(block.timestamp));
    if (vested <= released) return 0;
    return vested - released;
  }

  function release() external {
    require(msg.sender == beneficiary, "not beneficiary");
    uint256 amount = releasable();
    require(amount > 0, "nothing to release");

    // Safety check: ensure released won't exceed totalAllocation
    require(released + amount <= totalAllocation, "release exceeds allocation");

    // Check contract balance
    uint256 balance = token.balanceOf(address(this));
    require(balance >= amount, "insufficient contract balance");

    released += amount;
    bool ok = token.transfer(beneficiary, amount);
    require(ok, "transfer failed");

    uint256 remaining = totalAllocation - released;
    emit Released(amount, released, remaining);
  }

  // Emergency withdraw: allows beneficiary to withdraw all remaining tokens
  // Should only be used in extreme cases (e.g., token contract issues)
  function emergencyWithdraw() external {
    require(msg.sender == beneficiary, "not beneficiary");
    uint256 balance = token.balanceOf(address(this));
    require(balance > 0, "no balance");

    // Mark as fully released to prevent further releases
    released = totalAllocation;

    bool ok = token.transfer(beneficiary, balance);
    require(ok, "transfer failed");
    emit Released(balance, released, 0);
  }

  // --- View functions ---

  function totalReleased() public view returns (uint256) {
    return released;
  }

  function remaining() public view returns (uint256) {
    return totalAllocation - released;
  }

  function isFullyVested() public view returns (bool) {
    require(block.timestamp <= type(uint64).max, "timestamp overflow");
    return uint64(block.timestamp) >= start + durationSeconds;
  }

  function vestingEndTime() public view returns (uint64) {
    return start + durationSeconds;
  }

  function cliffEndTime() public view returns (uint64) {
    return start + cliffSeconds;
  }
}

contracts/launch/SafeLaunchToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * SafeLaunchToken
 *
 * Non-upgradeable ERC20. Deployed directly by TokenFactory via `new` (no proxy).
 * Because every token is a standalone contract (not an EIP-1167 clone), Etherscan
 * matches its bytecode to this verified source and marks it as verified automatically.
 *
 * GoPlus security check results:
 * ✓ is_proxy              = 0  — not a proxy; full contract bytecode deployed
 * ✓ is_open_source        = 1  — source verified via Etherscan bytecode match
 * ✓ slippage_modifiable   = 0  — fees locked at construction, no setters
 * ✓ is_blacklisted        = 0  — no blacklist
 * ✓ is_whitelisted        = 0  — no whitelist
 * ✓ is_anti_whale         = 0  — no tx/wallet limits
 * ✓ anti_whale_modifiable = 0  — (nothing to modify)
 * ✓ transfer_pausable     = 0  — no trading gate or pause function
 * ✓ external_call         = 0  — _update never calls external contracts;
 *                                fees are sent as tokens directly to marketingWallet
 * ✓ personal_slippage_modifiable = 0 — no per-address fee exemptions
 * ✓ is_mintable           = 0  — no public mint; supply fixed at construction
 * ✓ selfdestruct          = 0  — no self-destruct
 * ✓ hidden_owner          = 0  — standard Ownable
 * ✓ can_take_back_ownership = 0 — no reclaim mechanism
 * ✓ owner_change_balance  = 0  — owner cannot modify balances
 * ✓ is_honeypot           = 0  — no code blocks selling
 * ✓ cannot_sell_all       = 0  — full balance always sellable
 * ✓ trading_cooldown      = 0  — no cooldown
 */

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract SafeLaunchToken is ERC20, Ownable {
  // Marketing wallet receives all fee tokens directly during transfer.
  address public marketingWallet;

  // DEX pair — used only to distinguish buy vs sell for fee routing.
  // Setting this does not gate trading or affect transfer validity.
  address public uniswapV2Pair;

  // Fees stored in regular slots (not immutable) so that all deployed instances
  // share the same deployed bytecode → Etherscan auto-verifies via bytecode match.
  uint16 public buyFeeBps;
  uint16 public sellFeeBps;

  // Public flag: confirms fees cannot be changed (no setter exists).
  bool public constant feesLocked = true;

  event PairSet(address indexed pair);

  constructor(
    address initialOwner_,
    string memory name_,
    string memory symbol_,
    uint256 supplyRaw_,
    address marketingWallet_,
    uint16 buyFeeBps_,
    uint16 sellFeeBps_
  ) ERC20(name_, symbol_) Ownable(initialOwner_) {
    require(supplyRaw_ > 0,        "supply=0");
    require(buyFeeBps_  <= 2_000,  "buy fee > 20%");
    require(sellFeeBps_ <= 2_000,  "sell fee > 20%");

    marketingWallet = marketingWallet_ != address(0) ? marketingWallet_ : initialOwner_;
    buyFeeBps  = buyFeeBps_;
    sellFeeBps = sellFeeBps_;

    _mint(initialOwner_, supplyRaw_);
  }

  // -------------------------------------------------------------------------
  // Owner config — only the pair address; does not affect security posture
  // -------------------------------------------------------------------------

  /**
   * Set (or update) the DEX pair. Used only to identify buy/sell direction for
   * fee routing. Does not enable or disable trading.
   */
  function setPair(address pair_) external onlyOwner {
    uniswapV2Pair = pair_;
    emit PairSet(pair_);
  }

  // -------------------------------------------------------------------------
  // ERC20 transfer hook — fees go directly to marketingWallet as tokens.
  // No external contract calls (external_call = 0).
  // -------------------------------------------------------------------------

  function _update(address from, address to, uint256 amount) internal override {
    if (amount == 0) {
      super._update(from, to, amount);
      return;
    }

    address pair = uniswapV2Pair;

    // Identify buy/sell only when pair is configured.
    // Mint (from == 0) and burn (to == 0) are never treated as buy/sell.
    bool isBuy  = (pair != address(0) && from == pair && to   != address(0));
    bool isSell = (pair != address(0) && to   == pair && from != address(0));

    uint16 feeBps = 0;
    if      (isBuy)  feeBps = buyFeeBps;
    else if (isSell) feeBps = sellFeeBps;

    if (feeBps > 0) {
      uint256 feeAmount = (amount * feeBps) / 10_000;
      if (feeAmount > 0) {
        address mw = marketingWallet;
        if (mw == address(0)) mw = owner();
        // Direct token transfer: no external call, no reentrancy
        super._update(from, mw, feeAmount);
        super._update(from, to, amount - feeAmount);
        return;
      }
    }

    super._update(from, to, amount);
  }
}

contracts/launch/TokenFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * TokenFactory
 *
 * Deploys SafeLaunchToken instances via `new` (no proxy / no clone).
 *
 * Why `new` instead of Clones (EIP-1167)?
 * - EIP-1167 creates a minimal proxy whose bytecode only delegates to the
 *   implementation. Etherscan shows it as "Read/Write Contract as Proxy" and
 *   GoPlus flags is_proxy = 1 + is_open_source = 0 (source not verified for
 *   the proxy shell itself).
 * - With `new SafeLaunchToken(...)`, every deployed token IS the full contract.
 *   Etherscan matches the identical deployed bytecode to this verified source
 *   and marks each token as verified automatically (bytecode-match verification).
 *   Result: is_proxy = 0, is_open_source = 1.
 *
 * Vesting vaults still use Clones because they are internal infrastructure
 * (beneficiaries interact with them directly, not traded on-chain).
 *
 * ABI-compatible with previous factory:
 *   - TokenConfig still has `fees` (6 BPS sub-fields) and `limits` structs.
 *   - `limits` is accepted for ABI compatibility but not applied (token has no limits).
 *   - Buy/sell fee totals are derived by summing the 3 BPS sub-fields each.
 */

import "@openzeppelin/contracts/proxy/Clones.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

import "./SafeLaunchToken.sol";
import "./LinearVestingVaultUpgradeable.sol";

contract TokenFactory is ReentrancyGuard {
  using SafeERC20 for IERC20;

  event TokenCreated(address indexed creator, address indexed token);
  event TokenDistributed(address indexed token, address indexed to, uint256 amount);
  event VestingCreated(address indexed token, address indexed vault, address indexed beneficiary, uint256 amount);
  event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
  event FeesUpdated(
    uint256 oldBasicFeeWei,
    uint256 oldDistributionFeeWei,
    uint256 oldVestingFeeWei,
    uint256 newBasicFeeWei,
    uint256 newDistributionFeeWei,
    uint256 newVestingFeeWei
  );
  event FeesWithdrawn(address indexed to, uint256 amountWei);

  // Vesting vaults are still clone-based (internal infra, not traded tokens).
  address public immutable vestingImplementation;

  address public owner;
  uint256 public basicFeeWei;         // createToken
  uint256 public distributionFeeWei;  // createTokenWithDistribution
  uint256 public vestingFeeWei;       // createTokenWithDistributionAndVesting

  modifier onlyOwner() {
    require(msg.sender == owner, "not owner");
    _;
  }

  constructor(address vestingImplementation_) {
    require(vestingImplementation_ != address(0), "vestingImpl=0");
    vestingImplementation = vestingImplementation_;
    owner = msg.sender;
    emit OwnershipTransferred(address(0), msg.sender);

    basicFeeWei        = 0.0001 ether;
    distributionFeeWei = 0.001 ether;
    vestingFeeWei      = 0.005 ether;
  }

  function transferOwnership(address newOwner) external onlyOwner {
    require(newOwner != address(0), "owner=0");
    address prev = owner;
    owner = newOwner;
    emit OwnershipTransferred(prev, newOwner);
  }

  function setFeesWei(
    uint256 newBasicFeeWei,
    uint256 newDistributionFeeWei,
    uint256 newVestingFeeWei
  ) external onlyOwner {
    require(newBasicFeeWei        <= 1 ether, "basic fee too high");
    require(newDistributionFeeWei <= 1 ether, "distribution fee too high");
    require(newVestingFeeWei      <= 1 ether, "vesting fee too high");

    uint256 oldBasic        = basicFeeWei;
    uint256 oldDistribution = distributionFeeWei;
    uint256 oldVesting      = vestingFeeWei;

    basicFeeWei        = newBasicFeeWei;
    distributionFeeWei = newDistributionFeeWei;
    vestingFeeWei      = newVestingFeeWei;

    emit FeesUpdated(oldBasic, oldDistribution, oldVesting, newBasicFeeWei, newDistributionFeeWei, newVestingFeeWei);
  }

  function withdrawFees(address payable to, uint256 amountWei) external onlyOwner nonReentrant {
    if (to == address(0)) to = payable(owner);
    uint256 amount = amountWei == 0 ? address(this).balance : amountWei;
    require(amount <= address(this).balance, "insufficient balance");

    emit FeesWithdrawn(to, amount);
    (bool ok, ) = to.call{ value: amount }("");
    require(ok, "withdraw failed");
  }

  function _requireFeePaid(uint256 feeWei) private view {
    if (feeWei == 0) {
      require(msg.value == 0, "no fee required");
    } else {
      require(msg.value == feeWei, "bad fee");
    }
  }

  // ---------------------------------------------------------------------------
  // Structs — ABI-compatible with the previous factory version.
  // ---------------------------------------------------------------------------

  struct TokenConfig {
    string name;
    string symbol;
    uint256 totalSupplyRaw;
    address marketingWallet;
    Fees fees;
    Limits limits; // accepted for ABI compatibility; not applied to the token
  }

  /**
   * Buy/sell fees split into marketing + liquidity + burn sub-fields.
   * The factory sums them into a single buyFeeBps / sellFeeBps and passes
   * the total to SafeLaunchToken, which routes everything to marketingWallet
   * as tokens (simple, no external-call risk).
   */
  struct Fees {
    uint16 buyMarketingBps;
    uint16 buyLiquidityBps;
    uint16 buyBurnBps;
    uint16 sellMarketingBps;
    uint16 sellLiquidityBps;
    uint16 sellBurnBps;
  }

  /**
   * Kept for ABI compatibility only. SafeLaunchToken has no limit mechanism,
   * so these values are accepted but not applied:
   *   is_anti_whale = 0, anti_whale_modifiable = 0, trading_cooldown = 0.
   */
  struct Limits {
    uint256 maxGasPriceWei;
    uint256 deadBlocks;
    bool    revertEarlyBuys;
    uint256 maxTxAmount;
    uint256 maxWalletAmount;
  }

  struct Vesting {
    address beneficiary;
    uint64  start;
    uint64  cliffSeconds;
    uint64  durationSeconds;
    uint256 amount;
  }

  // ---------------------------------------------------------------------------
  // Internal helpers
  // ---------------------------------------------------------------------------

  function _sumFeeBps(Fees calldata f) private pure returns (uint16 buyTotal, uint16 sellTotal) {
    buyTotal  = f.buyMarketingBps  + f.buyLiquidityBps  + f.buyBurnBps;
    sellTotal = f.sellMarketingBps + f.sellLiquidityBps + f.sellBurnBps;
    require(buyTotal  <= 2_000, "buy fee > 20%");
    require(sellTotal <= 2_000, "sell fee > 20%");
  }

  function _deployToken(
    TokenConfig calldata cfg
  ) private returns (SafeLaunchToken token, address tokenAddr) {
    (uint16 buyBps, uint16 sellBps) = _sumFeeBps(cfg.fees);

    address marketing = cfg.marketingWallet != address(0) ? cfg.marketingWallet : msg.sender;

    // Deploy a full contract instance — NOT a proxy.
    // Each token has the same deployed bytecode → Etherscan auto-verifies via
    // bytecode match once this source is verified. is_proxy = 0.
    token = new SafeLaunchToken(
      address(this), // factory holds ownership until hand-off at end of create*
      cfg.name,
      cfg.symbol,
      cfg.totalSupplyRaw,
      marketing,
      buyBps,
      sellBps
    );
    tokenAddr = address(token);
  }

  function _deployVesting(address tokenAddr, Vesting calldata v) private returns (address vaultAddr) {
    vaultAddr = Clones.clone(vestingImplementation);
    LinearVestingVaultUpgradeable(vaultAddr).initialize(
      tokenAddr,
      v.beneficiary,
      v.start,
      v.cliffSeconds,
      v.durationSeconds,
      v.amount
    );
  }

  function _validateRecipientsAndSum(
    uint256 totalSupplyRaw,
    address[] calldata recipients,
    uint256[] calldata amounts
  ) private pure returns (uint256 sum) {
    require(recipients.length == amounts.length, "length mismatch");
    require(recipients.length <= 100, "too many recipients");
    for (uint256 i = 0; i < recipients.length; i++) {
      require(recipients[i] != address(0), "recipient=0");
      uint256 amt = amounts[i];
      if (amt == 0) continue;
      sum += amt;
    }
    require(sum <= totalSupplyRaw, "distribution > supply");
  }

  function _validateRecipientsVestingsAndSum(
    uint256 totalSupplyRaw,
    address[] calldata recipients,
    uint256[] calldata amounts,
    Vesting[] calldata vestings
  ) private pure returns (uint256 sum) {
    sum = _validateRecipientsAndSum(totalSupplyRaw, recipients, amounts);
    require(vestings.length <= 50, "too many vestings");
    for (uint256 j = 0; j < vestings.length; j++) {
      Vesting calldata v = vestings[j];
      require(v.beneficiary != address(0), "beneficiary=0");
      require(v.amount > 0, "vesting amount=0");
      sum += v.amount;
    }
    require(sum <= totalSupplyRaw, "distribution > supply");
  }

  // ---------------------------------------------------------------------------
  // Public entry points
  // ---------------------------------------------------------------------------

  /**
   * Deploy a bare token. All supply goes to msg.sender.
   */
  function createToken(TokenConfig calldata cfg) external payable returns (address tokenAddr) {
    _requireFeePaid(basicFeeWei);
    require(cfg.totalSupplyRaw > 0, "supply=0");

    SafeLaunchToken token;
    (token, tokenAddr) = _deployToken(cfg);

    token.transferOwnership(msg.sender);

    uint256 bal = token.balanceOf(address(this));
    if (bal > 0) {
      IERC20(tokenAddr).safeTransfer(msg.sender, bal);
    }

    emit TokenCreated(msg.sender, tokenAddr);
  }

  /**
   * Deploy token and distribute initial supply to multiple recipients.
   * Remaining supply (after recipients) goes to msg.sender.
   */
  function createTokenWithDistribution(
    TokenConfig calldata cfg,
    address[] calldata recipients,
    uint256[] calldata amounts
  ) external payable returns (address tokenAddr) {
    _requireFeePaid(distributionFeeWei);
    require(cfg.totalSupplyRaw > 0, "supply=0");
    _validateRecipientsAndSum(cfg.totalSupplyRaw, recipients, amounts);

    SafeLaunchToken token;
    (token, tokenAddr) = _deployToken(cfg);

    for (uint256 i = 0; i < recipients.length; i++) {
      uint256 amt = amounts[i];
      if (amt == 0) continue;
      IERC20(tokenAddr).safeTransfer(recipients[i], amt);
      emit TokenDistributed(tokenAddr, recipients[i], amt);
    }

    uint256 remaining = token.balanceOf(address(this));
    if (remaining > 0) {
      IERC20(tokenAddr).safeTransfer(msg.sender, remaining);
      emit TokenDistributed(tokenAddr, msg.sender, remaining);
    }

    token.transferOwnership(msg.sender);
    emit TokenCreated(msg.sender, tokenAddr);
  }

  /**
   * Deploy token, distribute some immediately, and vest the rest via
   * LinearVestingVault clones. Remaining supply goes to msg.sender.
   */
  function createTokenWithDistributionAndVesting(
    TokenConfig calldata cfg,
    address[] calldata recipients,
    uint256[] calldata amounts,
    Vesting[] calldata vestings
  ) external payable returns (address tokenAddr) {
    _requireFeePaid(vestingFeeWei);
    require(cfg.totalSupplyRaw > 0, "supply=0");
    _validateRecipientsVestingsAndSum(cfg.totalSupplyRaw, recipients, amounts, vestings);

    SafeLaunchToken token;
    (token, tokenAddr) = _deployToken(cfg);

    for (uint256 i = 0; i < recipients.length; i++) {
      uint256 amt = amounts[i];
      if (amt == 0) continue;
      IERC20(tokenAddr).safeTransfer(recipients[i], amt);
      emit TokenDistributed(tokenAddr, recipients[i], amt);
    }

    for (uint256 j = 0; j < vestings.length; j++) {
      Vesting calldata v = vestings[j];
      address vaultAddr = _deployVesting(tokenAddr, v);
      IERC20(tokenAddr).safeTransfer(vaultAddr, v.amount);
      emit VestingCreated(tokenAddr, vaultAddr, v.beneficiary, v.amount);
    }

    uint256 remaining = token.balanceOf(address(this));
    if (remaining > 0) {
      IERC20(tokenAddr).safeTransfer(msg.sender, remaining);
      emit TokenDistributed(tokenAddr, msg.sender, remaining);
    }

    token.transferOwnership(msg.sender);
    emit TokenCreated(msg.sender, tokenAddr);
  }
}

